    if i < 3:
        print(f'  businessid_{bus_id}: {desc[:100]}...')
    else:
        break

result = {
    'status': 'data_loaded',
    'reviews_count': len(reviews_data),
    'businesses_count': len(business_lookup),
    'reviewed_businesses_count': len(review_business_map)
}

print('__RESULT__:')
print(json.dumps(result))"}

